+fn parse_seed(raw: &str) -> Result<u64, Box<dyn std::error::Error>> {
+    let s = raw.trim();
+    let seed = if let Some(hex) = s.strip_prefix("0x").or_else(|| s.strip_prefix("0X")) {
+        let hex = hex.replace('_', "");
+        u64::from_str_radix(&hex, 16)?
+    } else {
+        let dec = s.replace('_', "");
+        dec.parse::<u64>()?
+    };
+    Ok(seed)
+}

